package assign;

public class AssignOperation {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=10;
		int b=4;
		int c=6;
		int d = 50;
		a %=9;
		b -=2;
		c *=10;
		d /= 5;
		System.out.println(a);
		System.out.println(b);
		System.out.println(c);
		System.out.println(d);
		a=10;
		a+=5;
		System.out.println(a);
		a*=6;
		System.out.println(a);
		a%=9;
		System.out.println(a);
		
		
	}

}
